class Solution:
    def letterCasePermutation(self, s):
        """
        :type s: str
        :rtype: List[str]
        """
        result = ['']

        for char in s:
            new_result = []
            if char.isalpha():
                for current in result:
                    new_result.append(current + char.lower())
                    new_result.append(current + char.upper())
            else:
                for current in result:
                    new_result.append(current + char)
            result = new_result

        return result
